async (params, browser) => {
  // Search for stores
  await browser.open(`https://www.walmart.com/store/finder?location=${params.location}`)

  // Wait for store results
  await browser.waitForSelector('[class*=\'store-card\'], [class*=\'store-list\'], [data-testid=\'store-card\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to see more stores
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract store information
  const store_data = await browser.evaluate(`const stores = []; const storeEls = document.querySelectorAll('[data-testid="store-card"], [class*="store-card"], [class*="store-list"] > div, [class*="store-item"]'); for (let i = 0; i < Math.min(storeEls.length, 10); i++) { const el = storeEls[i]; const nameEl = el.querySelector('[class*="store-name"], h2, h3, [class*="title"]'); const addressEl = el.querySelector('[class*="address"], address'); const phoneEl = el.querySelector('[class*="phone"], a[href^="tel:"]'); const hoursEl = el.querySelector('[class*="hours"], [class*="open-until"]'); const distEl = el.querySelector('[class*="distance"]'); const typeEl = el.querySelector('[class*="store-type"], [class*="badge"]'); const services = []; const serviceEls = el.querySelectorAll('[class*="service"] li, [class*="feature"] li, [class*="amenity"]'); serviceEls.forEach(function(s) { services.push(s.textContent.trim()); }); const linkEl = el.querySelector('a[href*="/store/"]'); stores.push({ name: nameEl ? nameEl.textContent.trim() : '', address: addressEl ? addressEl.textContent.trim() : '', phone: phoneEl ? phoneEl.textContent.trim() : '', hours: hoursEl ? hoursEl.textContent.trim() : '', distance: distEl ? distEl.textContent.trim() : '', store_type: typeEl ? typeEl.textContent.trim() : '', services: services.slice(0, 10), url: linkEl ? linkEl.href : '' }); } return { location: '' + params.location + '', store_count: stores.length, stores: stores, url: window.location.href }`)

  return store_data
}
